#!/usr/bin/perl
# Repair CCSS files generated by older versions of the csv2ccss converter
# which emitted non-standard CGATS fields (DISPLAY, TECHNOLOGY, SPECTRAL_NORM,
# SPEC_380...SPEC_780, etc.) without the required `KEYWORD "name"`
# declarations. ArgyllCMS/spotread silently drops these undeclared fields.
#
# Usage: fix_ccss_keywords.pl <dir> [<dir> ...]
# Safe to re-run: injects each KEYWORD only if missing.

use strict;
use warnings;

my @FIELDS = qw(
 DISPLAY TECHNOLOGY DISPLAY_TYPE_REFRESH REFERENCE
 SPECTRAL_BANDS SPECTRAL_START_NM SPECTRAL_END_NM SPECTRAL_NORM
);

sub fix_file {
 my ($path) = @_;
 open(my $fh, '<', $path) or do { warn "open $path: $!\n"; return 0; };
 my @lines = <$fh>;
 close($fh);

 # Only touch files produced by the buggy converter (keep X-Rite originals
 # and anything already well-formed untouched).
 my $is_pgen_converter = 0;
 for my $l (@lines[0..($#lines > 20 ? 20 : $#lines)]) {
  $is_pgen_converter = 1 if $l =~ /PGenerator\+\s+csv2ccss\s+converter/;
 }
 return 0 unless $is_pgen_converter;

 my %have_keyword;
 for my $l (@lines) {
  $have_keyword{$1} = 1 if $l =~ /^KEYWORD\s+"([^"]+)"/;
 }

 my @format_fields;
 my $in_data_format = 0;
 for my $l (@lines) {
  if ($l =~ /^BEGIN_DATA_FORMAT/) { $in_data_format = 1; next; }
  if ($l =~ /^END_DATA_FORMAT/)   { $in_data_format = 0; next; }
  next unless $in_data_format;
  for my $tok (split /\s+/, $l) {
   next unless $tok =~ /^(?:SAMPLE_ID|SPEC_\d+)$/;
   push @format_fields, $tok unless $have_keyword{$tok};
  }
 }

 my @out;
 my $format_keywords_added = 0;
 for (my $i = 0; $i < @lines; $i++) {
  my $line = $lines[$i];

  if (!$format_keywords_added && $line =~ /^NUMBER_OF_FIELDS\s/ && @format_fields) {
   for my $f (@format_fields) {
    next if $have_keyword{$f};
    push @out, qq(KEYWORD "$f"\n);
    $have_keyword{$f} = 1;
   }
   $format_keywords_added = 1;
  }

  my $matched;
  for my $f (@FIELDS) {
   if ($line =~ /^\Q$f\E\s/) { $matched = $f; last; }
  }
  if ($matched && !$have_keyword{$matched}) {
   push @out, qq(KEYWORD "$matched"\n);
   $have_keyword{$matched} = 1;
  }
  push @out, $line;
 }

 return 0 if join('', @out) eq join('', @lines);

 open(my $out, '>', $path) or do { warn "write $path: $!\n"; return 0; };
 print $out @out;
 close($out);
 return 1;
}

my $fixed = 0; my $scanned = 0;
for my $dir (@ARGV) {
 opendir(my $dh, $dir) or do { warn "opendir $dir: $!\n"; next; };
 while (my $f = readdir($dh)) {
  next unless $f =~ /\.ccss$/i;
  $scanned++;
  my $path = "$dir/$f";
  $fixed++ if fix_file($path);
 }
 closedir($dh);
}
print "scanned=$scanned fixed=$fixed\n";
